/** Single emoji with CLDR short name (from unicode.org/emoji/charts/full-emoji-list.html) */
export type EmojiItem = {
    icon: string;
    name: string;
};

export type EmojiGroup = {
    id: string;
    label: string;
    emojis: (EmojiItem | string | undefined)[];
};

export type Category = {
    id: string;
    name: string;
    namePl: string;
    groups: EmojiGroup[];
};

export function getCategoryEmojis(category: Category): (EmojiItem | string | undefined)[] {
    return category.groups.flatMap(g => g.emojis);
}

/** Normalize string or EmojiItem to EmojiItem for tooltip/display */
export function toEmojiItem(e: EmojiItem | string | undefined): EmojiItem | undefined {
    if (e == null) return undefined;
    if (typeof e === "string") return e === "" ? undefined : { icon: e, name: "Emoji" };
    return e.icon === "" ? undefined : e;
}

